#include "stdlib/constants/float64/pinf.h"
#include "stdlib/math/base/assert/is_nonnegative_integer.h"

/**
* Returns the excess kurtosis of a hypergeometric distribution.
*
* @param N    population size
* @param K    subpopulation size
* @param n    number of draws
* @return     kurtosis of the distribution, or NaN if inputs are invalid
*
* @example
* double k = stdlib_base_dists_hypergeometric_kurtosis( 16, 11, 4 );
* // returns ~-0.326
*/
double stdlib_base_dists_hypergeometric_kurtosis( const double N, const double K, const double n ) {
	if ( !stdlib_base_is_nonnegative_integer( N ) || !stdlib_base_is_nonnegative_integer( K ) || !stdlib_base_is_nonnegative_integer( n ) || N == STDLIB_CONSTANT_FLOAT64_PINF || K == STDLIB_CONSTANT_FLOAT64_PINF || K > N || n > N ) {
		return NAN;
	}

	double p = ( N - 1 ) * ( N * N ) * ( ( N * ( N + 1 ) ) - ( 6 * K * ( N - K ) ) - ( 6 * n * ( N - n ) ) );
	p += 6.0 * n * K * ( N - K ) * ( N - n ) * ( ( 5.0 * N ) - 6.0 );

	double q = n * K * ( N - K ) * ( N - n ) * ( N - 2 ) * ( N - 3 );

	return p / q;
}
